input.command:
ADMIN_PW=$(kubectl get secret admin-user-password -n mongodb -o jsonpath='{.data.password}' | base64 -d)
kubectl exec -n mongodb mongodb-replica-2 -- mongosh --quiet \
  "mongodb://admin-user:${ADMIN_PW}@localhost:27017/admin" \
  --eval '
    db.getSiblingDB("admin").createUser({
      user: "health-user",
      pwd: "healthpass123",
      roles: [{role: "clusterMonitor", db: "admin"}]
    });
    print("health-user created");
  ' 2>&1

kubectl patch statefulset mongodb-replica -n mongodb --type=strategic -p '{
  "spec": {
    "template": {
      "spec": {
        "containers": [{
          "name": "mongod",
          "env": [{
            "name": "HEALTH_USER_PASSWORD",
            "valueFrom": {
              "secretKeyRef": {
                "name": "health-user-password",
                "key": "password"
              }
            }
          }],
          "readinessProbe": {
            "exec": {
              "command": [
                "/bin/sh", "-c",
                "mongosh --quiet \"mongodb://health-user:$HEALTH_USER_PASSWORD@localhost:27017/admin\" --eval \"db.adminCommand({ping:1}).ok\" | grep -q 1"
              ]
            },
            "initialDelaySeconds": 20,
            "periodSeconds": 10,
            "timeoutSeconds": 5,
            "failureThreshold": 6,
            "successThreshold": 1
          },
          "livenessProbe": {
            "exec": {
              "command": [
                "/bin/sh", "-c",
                "mongosh --quiet \"mongodb://health-user:$HEALTH_USER_PASSWORD@localhost:27017/admin\" --eval \"db.adminCommand({ping:1}).ok\" | grep -q 1"
              ]
            },
            "initialDelaySeconds": 60,
            "periodSeconds": 20,
            "timeoutSeconds": 10,
            "failureThreshold": 3
          }
        }]
      }
    }
  }
}' 2>&1
